  9	  k8sCreate,
 10	} from '@openshift-console/dynamic-plugin-sdk';
 11	import { useParams, useNavigate } from 'react-router-dom-v5-compat';
 12	import { Form } from '@patternfly/react-core';
 13	import { FormFooter } from '../common/form-footer';
 14	import { getNodesByHostNameLabel } from '../local-volume-discovery/util';
 15	import { LocalVolumeSetBody } from './body';
 16	import { LocalVolumeSetHeader } from './header';
 17	import { initialState, reducer } from './state';
 18	
 19	const CreateLocalVolumeSet: React.FC = () => {
 20	  const { appName, ns } = useParams();
 21	  const resourcePath = resourcePathFromModel(
 22	    ClusterServiceVersionModel,
 23	    appName,
 24	    ns
 25	  );
 26	
 27	  const [state, dispatch] = React.useReducer(reducer, initialState);
 28	  const [nodesData, nodesLoaded, nodesLoadError] =
 29	    useK8sWatchResource<NodeKind[]>(nodeResource);
 30	  const navigate = useNavigate();
 31	  const [inProgress, setInProgress] = React.useState(false);
 32	  const [errorMessage, setErrorMessage] = React.useState('');
 33	
 34	  React.useEffect(() => {
 35	    if (nodesLoaded && !nodesLoadError && nodesData?.length !== 0) {
 36	      const filteredNodes: NodeKind[] = nodesData.filter(hasNoTaints);
 37	      dispatch({ type: 'setLvsAllNodes', value: filteredNodes });
 38	    }
 39	  }, [nodesData, nodesLoadError, nodesLoaded]);
 40	
 41	  const onSubmit = async (event: React.FormEvent<EventTarget>) => {
 42	    event.preventDefault();
 43	    setInProgress(true);
 44	
 45	    const lvsNodes = state.lvsIsSelectNodes
 46	      ? state.lvsSelectNodes
 47	      : state.lvsAllNodes;
 48	    const nodesByHostNameLabel = getNodesByHostNameLabel(lvsNodes);
 49	    const requestData = getLocalVolumeSetRequestData(
 50	      state,
 51	      nodesByHostNameLabel,
 52	      ns
 53	    );
 54	
 55	    k8sCreate({ model: LocalVolumeSetModel, data: requestData })
 56	      .then(() => {
 57	        navigate(
 58	          `/k8s/ns/${ns}/clusterserviceversions/${appName}/${referenceForModel(
 59	            LocalVolumeSetModel
 60	          )}/${state.volumeSetName}`
 61	        );
 62	      })
 63	      .catch((e) =>
 64	        e?.message
 65	          ? setErrorMessage(e.message)
 66	          : setErrorMessage(JSON.stringify(e))
 67	      );
 68	  };
 69	
 70	  const getDisabledCondition = () => {
 71	    const nodes = state.lvsIsSelectNodes
 72	      ? state.lvsSelectNodes
 73	      : state.lvsAllNodes;
 74	    if (!state.volumeSetName.trim().length) return true;
 75	    if (nodes.length < 1) return true;
 76	    if (!state.isValidDiskSize) return true;
 77	    return false;
 78	  };
 79	
 80	  return (
 81	    <>
 82	      <div className="odf-create-operand__header">
 83	        <LocalVolumeSetHeader className="odf-create-operand__header-text" />
 84	      </div>
 85	      <Form
 86	        noValidate={false}
 87	        className="odf-m-pane__body pf-v6-u-w-75"
 88	        onSubmit={onSubmit}
 89	      >
 90	        <LocalVolumeSetBody
 91	          dispatch={dispatch}
 92	          state={state}
 93	          storageClassName={''}
 94	        />
